function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function renderOrders(orders) {
  var tbody = document.getElementById('orders_body');
  if (!tbody) return;
  if (!orders || !orders.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty">No pending orders</td></tr>';
    return;
  }
  tbody.innerHTML = orders.map(function (o) {
    var statusClass = o.status === 'Received' ? 'badge-received' : o.status === 'Cancelled' ? 'badge-cancelled' : 'badge-pending';
    var action = o.status === 'Pending' ? '<button class="btn btn-order" style="height:28px;font-size:11px;padding:0 10px" onclick="window.markReceived(' + o.order_id + ')">Mark Received & Fit</button>' : '—';
    return '<tr>' + '<td>' + (o.part_description || '—') + '</td>' + '<td>' + (o.supplier || '—') + '</td>' + '<td style="font-family:monospace;font-size:11px">' + (o.order_ref || '—') + '</td>' + '<td>' + (o.unit_cost ? '£' + Number(o.unit_cost).toFixed(2) : '—') + '</td>' + '<td>' + fmt(o.expected_delivery) + '</td>' + '<td><span class="badge ' + statusClass + '">' + (o.status || 'Pending') + '</span></td>' + '<td>' + action + '</td>' + '</tr>';
  }).join('');
}
function populatePartTypes(types) {
  var sel1 = document.getElementById('scrap_part_type');
  var sel2 = document.getElementById('order_part_type');
  var opts = '<option value="">Select part type...</option>' + (types || []).map(function (t) {
    return '<option value="' + t.part_type_id + '">' + t.name + '</option>';
  }).join('');
  if (sel1) sel1.innerHTML = opts;
  if (sel2) sel2.innerHTML = opts;
}
function populateScrapLocations(locations) {
  var sel = document.getElementById('scrap_location');
  if (!sel) return;
  sel.innerHTML = '<option value="">Select location...</option>' + (locations || []).map(function (l) {
    return '<option value="' + l.location_id + '">' + l.location_code + ' — ' + l.location_name + '</option>';
  }).join('');
}
window.requestPart = function () {
  var desc = document.getElementById('request_part_desc').value.trim();
  if (!desc) {
    alert('Please describe the part needed');
    return;
  }
  appsmith.updateModel({
    requestedPartDesc: desc
  });
  appsmith.triggerEvent('onRequestPart');
  document.getElementById('request_part_desc').value = '';
  var msg = document.getElementById('request_success');
  if (msg) {
    msg.style.display = 'block';
    setTimeout(function () {
      msg.style.display = 'none';
    }, 3000);
  }
};
window.logScrap = function () {
  var partTypeId = document.getElementById('scrap_part_type').value;
  var notes = document.getElementById('scrap_notes').value.trim();
  var byField = document.getElementById('scrap_by');
  var removedBy = byField ? byField.value.trim() : '';
  var locationId = document.getElementById('scrap_location').value;
  if (!partTypeId) {
    alert('Please select a part type');
    return;
  }
  if (!locationId) {
    alert('Please select a scrap location');
    return;
  }
  appsmith.updateModel({
    scrapPart: {
      part_type_id: partTypeId,
      notes: notes,
      removed_by: removedBy,
      location_id: locationId
    }
  });
  appsmith.triggerEvent('onLogScrap');
  document.getElementById('scrap_part_type').value = '';
  document.getElementById('scrap_notes').value = '';
  if (byField) byField.value = '';
  document.getElementById('scrap_location').value = '';
  var msg = document.getElementById('scrap_success');
  if (msg) {
    msg.style.display = 'block';
    setTimeout(function () {
      msg.style.display = 'none';
    }, 3000);
  }
};
window.raiseOrder = function () {
  var partTypeId = document.getElementById('order_part_type').value;
  var desc = document.getElementById('order_desc').value.trim();
  var supplier = document.getElementById('order_supplier').value.trim();
  if (!partTypeId) {
    alert('Please select a part type');
    return;
  }
  if (!desc) {
    alert('Please enter a part description');
    return;
  }
  appsmith.updateModel({
    partsOrder: {
      part_type_id: partTypeId,
      part_description: desc,
      supplier: supplier,
      order_ref: document.getElementById('order_ref').value.trim(),
      unit_cost: parseFloat(document.getElementById('order_cost').value) || 0,
      quantity: parseInt(document.getElementById('order_qty').value) || 1,
      expected_delivery: document.getElementById('order_delivery').value || null,
      notes: document.getElementById('order_notes').value.trim()
    }
  });
  appsmith.triggerEvent('onRaiseOrder');
  document.getElementById('order_part_type').value = '';
  document.getElementById('order_desc').value = '';
  document.getElementById('order_supplier').value = '';
  document.getElementById('order_ref').value = '';
  document.getElementById('order_cost').value = '';
  document.getElementById('order_qty').value = '1';
  document.getElementById('order_delivery').value = '';
  document.getElementById('order_notes').value = '';
  var msg = document.getElementById('order_success');
  if (msg) {
    msg.style.display = 'block';
    setTimeout(function () {
      msg.style.display = 'none';
    }, 3000);
  }
};
window.markReceived = function (orderId) {
  appsmith.updateModel({
    receivingOrderId: orderId
  });
  appsmith.triggerEvent('onMarkReceived');
};
function render(model) {
  populatePartTypes(model.partTypes || []);
  populateScrapLocations(model.scrapLocations || []);
  renderOrders(model.orders || []);
  const byField = document.getElementById('scrap_by');
  if (byField) byField.value = model.currentUser || '';
}
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

